// ── Utility functions ─────────────────────────────────────────────────────────
const uid = () => 'x' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
const nowStr = () => new Date().toLocaleString('en-GB');
const todayStr = () => new Date().toLocaleDateString('en-GB');
const ini = (n) => (n||'?').trim().split(/\s+/).map(w=>w[0]||'').join('').slice(0,2).toUpperCase();
const gradeOf = (t) => { t=parseFloat(t); if(isNaN(t))return''; if(t>=75)return'A'; if(t>=60)return'B'; if(t>=50)return'C'; if(t>=40)return'D'; return'F'; };
const remarkOf = (g) => ({A:'EXCELLENT',B:'V.GOOD',C:'GOOD',D:'FAIR',F:'FAIL'}[g]||'');
const termName = (t) => (['','First','Second','Third'][parseInt(t)||2])+' Term';
