const AK_ = (sid,term,sess) => `aff:${sid}:${term}:${sess}`;
function hashPw(s) { let h=0; for(let i=0;i<s.length;i++) h=Math.imul(31,h)+s.charCodeAt(i)|0; return h.toString(36); }
const csvDl = (rows, name) => {
  const csv = rows.map(r=>r.map(c=>`"${String(c||'').replace(/"/g,'""')}"`).join(',')).join('\r\n');
  const a = document.createElement('a'); a.href = URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8;'}));
  a.download = name+'.csv'; document.body.appendChild(a); a.click(); document.body.removeChild(a);
};

// ── Storage ───────────────────────────────────────────────────────────────────
function loadDB() {
  let raw = null;
  try { raw = localStorage.getItem(SK); } catch(e) {}
  if(!raw) try { raw = sessionStorage.getItem(SK); } catch(e) {}
  if(!raw) return getInitialDB();
  try {
    const p = JSON.parse(raw);
    const init = getInitialDB();
    return { ...init, ...p, settings: { ...init.settings, ...(p.settings||{}) } };
  } catch(e) { return getInitialDB(); }
}
function saveDB(db) {
  const raw = JSON.stringify(db);
  try { localStorage.setItem(SK, raw); } catch(e) {}
  try { sessionStorage.setItem(SK, raw); } catch(e) {}
}

// ── Hooks ─────────────────────────────────────────────────────────────────────
function useDB() {
  const [db, setDbState] = useState(() => loadDB());
  const setDb = useCallback((upd) => {
    setDbState(prev => {
      const next = typeof upd === 'function' ? upd(prev) : upd;
      saveDB(next); return next;
    });
  }, []);
  return [db, setDb];
}

function useToast() {
  const [t, setT] = useState(null);
  const show = useCallback((msg,type='inf',dur=3200) => {
    setT({ msg, type, id: Date.now() });
    setTimeout(() => setT(null), dur);
  }, []);
  return [t, show];
}

function useClock() {
  const [time, setTime] = useState('');
  useEffect(() => {
    const tick = () => setTime(new Date().toLocaleString('en-GB',{weekday:'short',year:'numeric',month:'short',day:'numeric',hour:'2-digit',minute:'2-digit',second:'2-digit'}));
    tick(); const t = setInterval(tick, 1000); return () => clearInterval(t);
  }, []);
  return time;
}

