// ── News Ticker ────────────────────────────────────────────────────────────────
function NewsTicker({ news }) {
  const items = (news||[]).filter(n=>n.active!==false);
  if(!items.length) return null;
  const all = [...items,...items];
  return (
    <div style={{background:'linear-gradient(90deg,#1e6b52,#1a5f8a)',color:'#fff',height:34,display:'flex',alignItems:'center',overflow:'hidden',flexShrink:0}}>
      <div style={{background:'#c4952a',padding:'0 14px',height:'100%',display:'flex',alignItems:'center',fontSize:12,fontWeight:700,textTransform:'uppercase',letterSpacing:'.5px',flexShrink:0}}>📱 NEWS</div>
      <div style={{overflow:'hidden',flex:1,height:'100%',display:'flex',alignItems:'center'}}>
        <div style={{display:'flex',gap:60,animation:'ticker 40s linear infinite',whiteSpace:'nowrap',paddingLeft:20}}>
          {all.map((n,i)=><span key={i} style={{fontSize:13,opacity:.95,marginRight:60}}>📌 {n.title}{n.content?' — '+n.content.slice(0,60):''}</span>)}
        </div>
      </div>
      <style>{`@keyframes ticker{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}`}</style>
    </div>
  );
}

// ── Events Bar ─────────────────────────────────────────────────────────────────
function EventsBar({ events }) {
  const upcoming = (events||[]).filter(ev=>{try{return new Date(ev.date.split('/').reverse().join('-'))>=new Date();}catch(e){return true;}}).slice(0,8);
  if(!upcoming.length) return null;
  return (
    <div style={{background:'#fdf6e3',borderBottom:'1px solid #c4952a',padding:'6px 20px',display:'flex',alignItems:'center',gap:10,overflowX:'auto',flexShrink:0}}>
      <span style={{fontSize:11,fontWeight:700,color:'#c4952a',textTransform:'uppercase',letterSpacing:'.5px',flexShrink:0}}>📅 Upcoming:</span>
      {upcoming.map(ev=>(
        <div key={ev.id} style={{background:'#fff',border:'1px solid #c4952a',borderRadius:50,padding:'3px 12px',fontSize:12,fontWeight:500,color:'#c4952a',whiteSpace:'nowrap',flexShrink:0}}>
          <strong style={{color:'#1e6b52'}}>{ev.date}</strong> {ev.name}
        </div>
      ))}
    </div>
  );
}

