// ── RESULT UTILITIES ──────────────────────────────────────────────────────────
function getStuScores(db, stuId, term, sess) {
  return db.subjects.map(s=>{
    const k=SK_(stuId,s.name,term,sess); const sc=db.scores[k];
    if(!sc) return null;
    const ca1=parseFloat(sc.ca1)||0, ca2=parseFloat(sc.ca2)||0, exam=parseFloat(sc.exam)||0, tot=ca1+ca2+exam;
    if(tot===0&&!sc.ca1&&!sc.ca2&&!sc.exam) return null;
    return {name:s.name,section:s.section||'',ca1,ca2,exam,total:tot,grade:gradeOf(tot),remark:remarkOf(gradeOf(tot)),status:sc.status||'draft'};
  }).filter(Boolean);
}

function getClassPos(db, stuId, cls, term, sess) {
  const arr = db.students.filter(s=>s.cls===cls).map(cs=>{
    const sc=getStuScores(db,cs.id,term,sess); const tot=sc.reduce((a,s)=>a+s.total,0);
    return {id:cs.id, avg: sc.length ? tot/sc.length : 0};
  }).sort((a,b)=>b.avg-a.avg);
  return arr.findIndex(x=>x.id===stuId)+1;
}

function getAllResultRecords(db) {
  const seen={}, results=[];
  db.students.forEach(st=>{
    Object.keys(db.scores).forEach(k=>{
      const [sid,,term,sess]=k.split(':');
      if(sid!==st.id) return;
      const rkey=`${sid}:${term}:${sess}`;
      if(!seen[rkey]){ seen[rkey]=true; results.push({student:st,term,session:sess,status:db.scores[k].status||'draft',teacher:db.scores[k].teacher||''}); }
    });
  });
  return results;
}

