function ImportStudentsModal({ db, setDb, toast, onClose }) {
  const [file,setFile]=useState(null); const [preview,setPreview]=useState([]);
  const handleFile=e=>{ const f=e.target.files[0]; if(!f)return; setFile(f); const rd=new FileReader(); rd.onload=ev=>{const lines=ev.target.result.split(/\r?\n/).filter(l=>l.trim());setPreview(lines.slice(0,4));};rd.readAsText(f); };
  const doImport=()=>{
    if(!file)return;
    const rd=new FileReader();
    rd.onload=ev=>{
      const lines=ev.target.result.split(/\r?\n/).filter(l=>l.trim()); let added=0,skip=0;
      const newStudents=[...db.students];
      lines.forEach((ln,i)=>{
        if(i===0&&ln.toLowerCase().includes('admno'))return;
        const c=ln.split(',');
        const [adm,name,sex,dob,age,cls,house,parName,parPhone,parUser,parPass]=(c.map(x=>(x||'').trim()));
        if(!name||!adm||!cls){skip++;return;}
        if(newStudents.find(x=>x.admNo.toLowerCase()===adm.toLowerCase())){skip++;return;}
        const pin=String(Math.floor(1000+Math.random()*9000));
        newStudents.push({id:uid(),name,admNo:adm,sex,dob,age,cls,house,parentName:parName,parentPhone:parPhone,parentUsername:parUser||'',parentPassword:parPass?hashPw(parPass):'',resumption:'',pin,pinUses:0,photo:null,createdAt:nowStr()});
        added++;
      });
      setDb(prev=>({...prev,students:newStudents})); toast(`Imported: ${added}, skipped: ${skip}`,'suc'); onClose();
    };
    rd.readAsText(file);
  };
  return (
    <Modal title="Import Students (CSV)" size="lg" onClose={onClose} actions={[{label:'Import',cls:'pri',fn:doImport}]}>
      <div style={{background:'#e8f2f9',border:'1px solid #1a5f8a',borderRadius:8,padding:'9px 12px',fontSize:12,color:'#1a5f8a',marginBottom:10}}>CSV columns: admNo, name, sex, dob, age, cls, house, parentName, parentPhone, parentUsername, parentPassword</div>
      <div style={{background:'#f8f9fa',borderRadius:6,padding:'8px 10px',fontFamily:'monospace',fontSize:11,color:'#8892a4',marginBottom:12,border:'1px solid #e2e5ec'}}>AMS/001,John Doe,Male,01/01/2015,9,Primary 3,Red,Mrs Doe,0801234,john.parent,pass123</div>
      <Field label="Select CSV File"><input type="file" accept=".csv,.txt" onChange={handleFile} style={{color:'#1a1a2e',fontSize:13}}/></Field>
      {preview.length>0&&<><div style={{fontSize:12,fontWeight:700,marginBottom:6}}>Preview (first 4 rows):</div><div style={{background:'#f8f9fa',borderRadius:6,padding:8,fontFamily:'monospace',fontSize:11,maxHeight:80,overflowY:'auto'}}>{preview.map((l,i)=><div key={i}>{l}</div>)}</div></>}
    </Modal>
  );
}

