function SigModal({ teacher, onSave, onClose, toast }) {
  const [b64,setB64]=useState(''); const [prev,setPrev]=useState(teacher.signature||'');
  const handleFile=e=>{
    const f=e.target.files[0]; if(!f)return;
    if(f.size>600*1024){toast('Max 600KB','err');return;}
    if(!f.type.startsWith('image/')){toast('Select an image file','err');return;}
    const rd=new FileReader();
    rd.onload=ev=>{setB64(ev.target.result);setPrev(ev.target.result);};
    rd.onerror=()=>toast('Could not read file','err');
    rd.readAsDataURL(f);
  };
  return (
    <Modal title={`Signature: ${teacher.name}`} size="sm" onClose={onClose} actions={[{label:'Save Signature',cls:'pri',fn:()=>{if(!b64){toast('Select an image first','err');return;}onSave(teacher.id,b64);}},{label:'Remove',cls:'dan',fn:()=>onSave(teacher.id,null)}]}>
      {prev&&<div style={{textAlign:'center',marginBottom:12,padding:8,background:'#f8f9fa',borderRadius:8,border:'1px solid #e2e5ec'}}><div style={{fontSize:11,color:'#8892a4',marginBottom:4}}>{b64?'New signature preview:':'Current signature:'}</div><img src={prev} style={{maxHeight:55,maxWidth:180,objectFit:'contain'}} alt="sig"/></div>}
      <Field label="Signature Image (PNG recommended, max 600KB)">
        <input type="file" accept="image/*" onChange={handleFile} style={{display:'block',marginTop:6,color:'#1a1a2e',fontSize:13,padding:'6px 0'}}/>
      </Field>
    </Modal>
  );
}

