// ── PAGE: RESULTS ─────────────────────────────────────────────────────────────
function ResultsPage({ db, setDb, session, toast, onViewPrint }) {
  const {role,user}=session;
  const isAdmin=()=>['super-admin','deputy-admin'].includes(role);
  const [q,setQ]=useState(''); const [fcls,setFcls]=useState(''); const [fterm,setFterm]=useState(''); const [fsts,setFsts]=useState('');

  const all=getAllResultRecords(db).filter(r=>{
    const m=!q||(r.student.name.toLowerCase().includes(q.toLowerCase())||r.student.admNo.toLowerCase().includes(q.toLowerCase()));
    if(role==='primary'&&user.assignedClass) return r.student.cls===user.assignedClass&&m;
    if(role==='secondary-form'&&user.assignedClass) return r.student.cls===user.assignedClass&&m;
    if(role==='secondary-subject') return r.teacher===user.name&&m;
    return m&&(!fcls||r.student.cls===fcls)&&(!fterm||r.term===fterm)&&(!fsts||r.status===fsts);
  });

  const exportAll=()=>{
    const rows=[['Name','Adm No','Class','Term','Session','Subjects','Total','Average','Position','Class Size','Final Grade']];
    all.forEach(r=>{const sc=getStuScores(db,r.student.id,r.term,r.session);const tot=sc.reduce((a,s)=>a+s.total,0);const avg=sc.length?(tot/sc.length).toFixed(1):0;const pos=getClassPos(db,r.student.id,r.student.cls,r.term,r.session);const size=db.students.filter(s=>s.cls===r.student.cls).length;rows.push([r.student.name,r.student.admNo,r.student.cls,termName(r.term),r.session,sc.length,tot.toFixed(0),avg,pos,size,gradeOf(parseFloat(avg))]);});
    csvDl(rows,'all_results_'+todayStr().replace(/\//g,'-'));toast('Exported','suc');
  };

  const stsColors={draft:'gy',pending:'am',approved:'bl',locked:'gr'};
  return (
    <div style={{display:'flex',flexDirection:'column',gap:12}}>
      <PageHeader title="Results" sub={`${all.length} result(s)`}>
        <Btn sm onClick={exportAll}>📥 Export CSV</Btn>
      </PageHeader>
      <SearchBar>
        <SIF value={q} onChange={setQ} placeholder="🔍 Search student..."/>
        {isAdmin()&&<Select value={fcls} onChange={setFcls} style={{flex:'none',width:'auto'}} options={[{v:'',l:'All Classes'},...db.classes.map(c=>({v:c,l:c}))]}/>}
        <Select value={fterm} onChange={setFterm} style={{flex:'none',width:'auto'}} options={[{v:'',l:'All Terms'},{v:'1',l:'Term 1'},{v:'2',l:'Term 2'},{v:'3',l:'Term 3'}]}/>
        <Select value={fsts} onChange={setFsts} style={{flex:'none',width:'auto'}} options={[{v:'',l:'All Status'},{v:'draft',l:'Draft'},{v:'pending',l:'Pending'},{v:'approved',l:'Approved'},{v:'locked',l:'Locked'}]}/>
      </SearchBar>
      <Table cols={['Photo','Student','Adm. No.','Class','Term','Subj','Total','Avg','Pos','Grade','Status','Actions']}
        empty="No results found."
        rows={all.map((r,i)=>{
          const sc=getStuScores(db,r.student.id,r.term,r.session);
          const tot=sc.reduce((a,s)=>a+s.total,0); const avg=sc.length?(tot/sc.length).toFixed(1):0;
          const g=gradeOf(parseFloat(avg)); const pos=getClassPos(db,r.student.id,r.student.cls,r.term,r.session);
          const size=db.students.filter(s=>s.cls===r.student.cls).length;
          return <tr key={i}>
            <TD><PhotoCircle photo={r.student.photo} name={r.student.name} size={30}/></TD>
            <TD b>{r.student.name}</TD><TD mono sm>{r.student.admNo}</TD><TD>{r.student.cls}</TD><TD sm>{termName(r.term)}</TD>
            <TD mono>{sc.length}</TD><TD mono>{tot.toFixed(0)}</TD><TD mono b>{avg}%</TD>
            <TD mono b>{pos}/{size}</TD>
            <td style={{padding:'9px 12px'}}>{g?<Badge g={g}/>:'—'}</td>
            <td style={{padding:'9px 12px'}}><Badge g={stsColors[r.status]||'gy'} label={r.status}/></td>
            <td style={{padding:'9px 12px'}}><div style={{display:'flex',gap:3}}>
              <Btn xs cls="pri" onClick={()=>onViewPrint(r.student.id,r.term,r.session)}>🖨️</Btn>
              {isAdmin()&&r.status!=='locked'&&<Btn xs cls="blue" onClick={()=>{setDb(prev=>{const ns={...prev.scores};db.subjects.forEach(s=>{const k=SK_(r.student.id,s.name,r.term,r.session);if(ns[k])ns[k]={...ns[k],status:'locked'};});return {...prev,scores:ns};});toast('Locked','suc');}}>🔒</Btn>}
              {isAdmin()&&r.status==='locked'&&<Btn xs onClick={()=>{setDb(prev=>{const ns={...prev.scores};db.subjects.forEach(s=>{const k=SK_(r.student.id,s.name,r.term,r.session);if(ns[k])ns[k]={...ns[k],status:'approved'};});return {...prev,scores:ns};});toast('Unlocked','suc');}}>🔓</Btn>}
            </div></td>
          </tr>;
        })}
      />
    </div>
  );
}

