// ── PAGE: DAILY REPORTS ───────────────────────────────────────────────────────
function ReportsPage({ db, setDb, session, toast }) {
  const {role,user}=session;
  const isAdmin=()=>['super-admin','deputy-admin'].includes(role);
  const [modal,setModal]=useState(false);
  const list=(db.reports||[]).filter(r=>isAdmin()||r.teacherId===user.id).sort((a,b)=>b.date.localeCompare(a.date));
  const approve=(id)=>{setDb(prev=>({...prev,reports:prev.reports.map(r=>r.id===id?{...r,status:'approved',approvedAt:nowStr()}:r)}));toast('Approved','suc');};
  const reject=(id)=>{setDb(prev=>({...prev,reports:prev.reports.map(r=>r.id===id?{...r,status:'rejected'}:r)}));toast('Rejected','dan');};
  const del=(id)=>{if(!window.confirm('Delete?'))return;setDb(prev=>({...prev,reports:prev.reports.filter(r=>r.id!==id)}));};
  const stsStyle={pending:{background:'#fdf6e3',color:'#c4952a',border:'1px solid #c4952a'},approved:{background:'#e8f5f0',color:'#1e6b52',border:'1px solid #1e6b52'},rejected:{background:'#fde8e8',color:'#d63031',border:'1px solid #d63031'}};
  return (
    <div style={{display:'flex',flexDirection:'column',gap:12}}>
      <PageHeader title="Daily Reports" sub={isAdmin()?'All teacher reports':'Your submitted reports'}>
        {(role==='primary'||role==='secondary-subject'||role==='secondary-form')&&<Btn cls="pri" sm onClick={()=>setModal(true)}>+ Submit Report</Btn>}
      </PageHeader>
      {list.length===0&&<div style={{...S.card,textAlign:'center',color:'#8892a4',padding:40}}>No reports yet.</div>}
      {list.map(r=>{
        const t=db.teachers.find(x=>x.id===r.teacherId);
        const sts=r.status||'pending';
        return <div key={r.id} style={S.card}>
          <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',gap:10,flexWrap:'wrap'}}>
            <div><div style={{fontSize:14,fontWeight:700,color:'#1a1a2e',marginBottom:2}}>{r.title}</div><div style={{fontSize:12,color:'#8892a4'}}>{t?.name||'Unknown'} · {r.date} · {r.cls||''}</div></div>
            <div style={{display:'flex',gap:6,alignItems:'center'}}>
              <span style={{display:'inline-flex',padding:'3px 9px',borderRadius:50,fontSize:11,fontWeight:700,...(stsStyle[sts]||stsStyle.pending)}}>{sts}</span>
              {isAdmin()&&sts==='pending'&&<><Btn xs cls="pri" onClick={()=>approve(r.id)}>✅ Approve</Btn><Btn xs cls="dan" onClick={()=>reject(r.id)}>✕ Reject</Btn></>}
              {!isAdmin()&&sts==='pending'&&<Btn xs cls="dan" onClick={()=>del(r.id)}>🗑</Btn>}
            </div>
          </div>
          <div style={{fontSize:13,color:'#4a4e69',marginTop:8,lineHeight:1.6}}>{r.content}</div>
        </div>;
      })}
      {modal&&<ReportModal session={session} setDb={setDb} toast={toast} onClose={()=>setModal(false)}/>}
    </div>
  );
}
function ReportModal({ session, setDb, toast, onClose }) {
  const [title,setTitle]=useState(''); const [cls,setCls]=useState(session.user.assignedClass||''); const [date,setDate]=useState(todayStr()); const [content,setContent]=useState('');
  const save=()=>{
    if(!title||!content){alert('Title and content required.');return;}
    setDb(prev=>({...prev,reports:[{id:uid(),title,content,cls,date,teacherId:session.user.id,teacherName:session.user.name,status:'pending',createdAt:nowStr()},...prev.reports]}));
    toast('Report submitted','suc'); onClose();
  };
  return (
    <Modal title="Submit Daily Report" size="md" onClose={onClose} actions={[{label:'Submit Report',cls:'pri',fn:save}]}>
      <Field label="Report Title *"><Input value={title} onChange={setTitle} placeholder="e.g. Class Activities - Monday 15th April"/></Field>
      <Fr2><Field label="Class"><Input value={cls} onChange={setCls}/></Field><Field label="Date"><Input value={date} onChange={setDate} placeholder="DD/MM/YYYY"/></Field></Fr2>
      <Field label="Report Content *"><Textarea value={content} onChange={setContent} rows={5} placeholder="Describe what happened in class today, topics covered, student behavior, issues, achievements, etc."/></Field>
    </Modal>
  );
}

