// ── PAGE: PARENT HOME ─────────────────────────────────────────────────────────
function ParentHomePage({ db, setDb, session, toast, onViewPrint }) {
  const st=session.user.student;
  const refreshedStudent=db.students.find(s=>s.id===st.id)||st;
  const hasPhoto=!!refreshedStudent.photo;
  const [tab,setTab]=useState(hasPhoto?'results':'photo');

  const savePhoto=(b64)=>{setDb(prev=>({...prev,students:prev.students.map(s=>s.id===refreshedStudent.id?{...s,photo:b64}:s)}));toast('Photo saved!','suc');setTab('results');};

  const found=[];
  ['1','2','3'].forEach(term=>{
    [db.settings.session,'2022/2023'].forEach(sess=>{
      const sc=getStuScores(db,refreshedStudent.id,term,sess);if(sc.length)found.push({term,sess,scores:sc});
    });
  });

  const downloadResult=(stuId,term,sess)=>{
    const sc=getStuScores(db,stuId,term,sess);if(!sc.length){toast('No scores','war');return;}
    toast('Use Print → Save as PDF to download','inf',5000);onViewPrint(stuId,term,sess);
  };

  return (
    <div style={{display:'flex',flexDirection:'column',gap:14}}>
      <div style={{...S.card,display:'flex',alignItems:'center',gap:14}}>
        <PhotoCircle photo={refreshedStudent.photo} name={refreshedStudent.name} size={60} borderColor='#1e6b52'/>
        <div>
          <div style={{fontFamily:'Georgia,serif',fontSize:18,fontWeight:700}}>{refreshedStudent.name}</div>
          <div style={{fontSize:12,color:'#8892a4'}}>{refreshedStudent.cls} · Adm: {refreshedStudent.admNo}</div>
        </div>
      </div>

      {!hasPhoto&&<div style={{...S.card,border:'2px solid #c4952a',background:'#fdf6e3'}}>
        <div style={{fontSize:14,fontWeight:700,color:'#c4952a',marginBottom:6}}>📸 Photo Required</div>
        <div style={{fontSize:12,color:'#7d6008',marginBottom:12}}>Please upload your child's photo before accessing results. This is required for identification in the classroom view and result sheet.</div>
        <PhotoUploader onSave={savePhoto} toast={toast}/>
      </div>}

      {hasPhoto&&(
        <>
          <div style={{display:'flex',gap:2,borderBottom:'1px solid #e2e5ec',marginBottom:2}}>
            {[{id:'results',l:'📊 Results'},{id:'photo',l:'📷 Update Photo'}].map(t=><div key={t.id} onClick={()=>setTab(t.id)} style={{padding:'8px 15px',fontSize:13,fontWeight:600,color:tab===t.id?'#1e6b52':'#8892a4',cursor:'pointer',borderBottom:tab===t.id?'2px solid #1e6b52':'2px solid transparent',marginBottom:-1}}>{t.l}</div>)}
          </div>
          {tab==='results'&&(
            found.length===0?<div style={{...S.card,textAlign:'center',color:'#8892a4',padding:40}}>No results available yet.</div>:
            found.map((r,i)=>{
              const tot=r.scores.reduce((a,s)=>a+s.total,0); const avg=r.scores.length?(tot/r.scores.length).toFixed(1):0;
              const g=gradeOf(parseFloat(avg)); const pos=getClassPos(db,refreshedStudent.id,refreshedStudent.cls,r.term,r.sess);
              const size=db.students.filter(s=>s.cls===refreshedStudent.cls).length;
              return <div key={i} style={S.card}>
                <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:12,flexWrap:'wrap',gap:8}}>
                  <div><div style={{fontSize:14,fontWeight:700}}>{termName(r.term)} · {r.sess}</div><div style={{fontSize:12,color:'#8892a4'}}>{r.scores.length} subjects · Avg: {avg}% · Grade: {g} · Position: {pos}/{size}</div></div>
                  <div style={{display:'flex',gap:7}}><Btn cls="pri" sm onClick={()=>downloadResult(refreshedStudent.id,r.term,r.sess)}>📄 View &amp; Print</Btn></div>
                </div>
                <Table cols={['Subject','1st CA','2nd CA','Exam','Total','Grade','Remark']}
                  rows={r.scores.map(s=><tr key={s.name}><TD b>{s.name}</TD><TD mono>{s.ca1}</TD><TD mono>{s.ca2}</TD><TD mono>{s.exam}</TD><TD mono b>{s.total.toFixed(0)}</TD><td style={{padding:'9px 12px'}}><Badge g={s.grade}/></td><TD sm>{s.remark}</TD></tr>)}
                />
              </div>;
            })
          )}
          {tab==='photo'&&<div style={S.card}><PhotoUploader onSave={savePhoto} current={refreshedStudent.photo} toast={toast}/></div>}
        </>
      )}
    </div>
  );
}

function PhotoUploader({ onSave, current, toast }) {
  const [b64,setB64]=useState(''); const [prev,setPrev]=useState(current||'');
  const handle=e=>{const f=e.target.files[0];if(!f)return;if(f.size>1*1024*1024){if(toast)toast('Max 1MB','err');else alert('Max 1MB');return;}if(!f.type.startsWith('image/')){if(toast)toast('Select image file','err');else alert('Select image');return;}const rd=new FileReader();rd.onload=ev=>{setB64(ev.target.result);setPrev(ev.target.result);};rd.onerror=()=>{if(toast)toast('Could not read file','err');};rd.readAsDataURL(f);};
  return (
    <div>
      {prev?<div style={{textAlign:'center',marginBottom:14}}><img src={prev} style={{width:100,height:100,borderRadius:'50%',objectFit:'cover',border:'3px solid #1e6b52'}} alt="preview"/><div style={{fontSize:12,color:'#8892a4',marginTop:6}}>{b64?'New photo preview':'Current photo'}</div></div>:
      <div style={{border:'2px dashed #c8cdd8',borderRadius:12,padding:28,textAlign:'center',marginBottom:14,background:'#f8f9fa'}}><div style={{fontSize:48,marginBottom:10}}>📷</div><div style={{fontSize:14,fontWeight:600,color:'#1a1a2e',marginBottom:4}}>Upload Child's Photo</div><div style={{fontSize:12,color:'#8892a4'}}>JPG or PNG, max 1MB</div></div>}
      <label style={{display:'block',textAlign:'center',marginBottom:10}}>
        <span style={{display:'inline-flex',alignItems:'center',gap:5,padding:'8px 16px',borderRadius:8,border:'1.5px dashed #c8cdd8',background:'#f8f9fa',fontSize:13,fontWeight:600,cursor:'pointer',color:'#4a4e69'}}>📂 Select Photo File</span>
        <input type="file" accept="image/*" onChange={handle} style={{display:'none'}}/>
      </label>
      {b64&&<Btn cls="pri" onClick={()=>onSave(b64)} style={{width:'100%',justifyContent:'center'}}>✅ Save Photo</Btn>}
    </div>
  );
}

// ── PAGE: STUDENT VIEW ────────────────────────────────────────────────────────
function StudentViewPage({ db, session, onViewPrint }) {
  const st=session.user.student;
  const found=[];
  [db.settings.session].forEach(sess=>{ ['1','2','3'].forEach(term=>{const sc=getStuScores(db,st.id,term,sess);if(sc.length)found.push({term,sess,scores:sc});}); });
  return (
    <div style={{display:'flex',flexDirection:'column',gap:14}}>
      <div style={{fontSize:12,color:'#8892a4'}}>PIN uses remaining: {5-(st.pinUses||0)}/5</div>
      {found.length===0&&<div style={{...S.card,textAlign:'center',color:'#8892a4',padding:40}}>No results available yet. Contact your class teacher.</div>}
      {found.map((r,i)=>{const tot=r.scores.reduce((a,s)=>a+s.total,0);const avg=r.scores.length?(tot/r.scores.length).toFixed(1):0;const g=gradeOf(parseFloat(avg));return <div key={i} style={S.card}><div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:10}}><div><div style={{fontSize:14,fontWeight:700}}>{termName(r.term)} · {r.sess}</div><div style={{fontSize:12,color:'#8892a4'}}>Average: {avg}% · Grade: {g}</div></div><Btn cls="pri" sm onClick={()=>onViewPrint(st.id,r.term,r.sess)}>🖨️ Print</Btn></div><Table cols={['Subject','1st CA','2nd CA','Exam','Total','Grade']} rows={r.scores.map(s=><tr key={s.name}><TD b>{s.name}</TD><TD mono>{s.ca1}</TD><TD mono>{s.ca2}</TD><TD mono>{s.exam}</TD><TD mono b>{s.total.toFixed(0)}</TD><td style={{padding:'9px 12px'}}><Badge g={s.grade}/></td></tr>)}/></div>;})}
    </div>
  );
}

// ── MAIN APP ──────────────────────────────────────────────────────────────────
export default function App() {
  const [db, setDb] = useDB();
  const [session, setSession] = useState(null);
  const [page, setPage] = useState('dash');
  const [toast_, showToast] = useToast();
  const [printData, setPrintData] = useState(null);
  const clock = useClock();

  const handleLogin = useCallback((ses) => {
    if(ses.pinUpdate) setDb(prev=>({...prev,students:prev.students.map(s=>s.id===ses.pinUpdate?{...s,pinUses:(s.pinUses||0)+1}:s)}));
    setDb(prev=>({...prev,logs:[{id:uid(),user:ses.user.username||ses.user.admNo||'user',role:ses.role,event:'Login',detail:ses.user.name,time:nowStr()},...prev.logs].slice(0,600)}));
    setSession(ses);
    setPage(ses.loginType==='parent'?'parent-home':ses.loginType==='student'?'student-view':'dash');
  }, [setDb]);

  const handleLogout=()=>{setSession(null);setPage('dash');setPrintData(null);};
  const handleViewPrint=(sid,term,sess)=>{setPrintData({sid,term,sess});setPage('print');};

  const pageLabels={dash:'Dashboard',news:'News',events:'Events',students:'Students',teachers:'Teachers',admins:'Admin Users',subjects:'Subjects',entry:'Enter Results',affective:'Affective & Psychomotor',results:'Results',classroom:'Classroom View',approval:'Approve Results',reports:'Daily Reports',settings:'Settings',logs:'Audit Log','parent-home':'Parent Portal','student-view':'My Results',print:'Result Sheet'};

  const isAdmin=()=>session&&['super-admin','deputy-admin'].includes(session.role);

  useEffect(()=>{
    if(db.settings.themeColor) document.documentElement.style.setProperty('--primary',db.settings.themeColor);
    if(db.settings.bgColor) document.body.style.background=db.settings.bgColor;
  },[db.settings.themeColor,db.settings.bgColor]);

  if(!session) return (
    <>
      <NewsTicker news={db.news}/><EventsBar events={db.events}/>
      <LoginPage db={db} onLogin={handleLogin}/>
      <Toast t={toast_}/>
    </>
  );

  return (
    <div style={{display:'flex',minHeight:'100vh'}}>
      <style>{`@keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}:root{--primary:#1e6b52}`}</style>
      <Sidebar session={session} page={page} onNav={(p)=>{setPage(p);setPrintData(null);}} onLogout={handleLogout} db={db}/>
      <div style={{flex:1,minHeight:'100vh',overflowY:'auto',background:db.settings.bgColor||'#f5f7fa',display:'flex',flexDirection:'column'}}>
        <NewsTicker news={db.news}/><EventsBar events={db.events}/>
        <div style={{background:'#fff',borderBottom:'1px solid #e2e5ec',padding:'10px 22px',display:'flex',alignItems:'center',gap:12,flexShrink:0}}>
          <div style={{fontFamily:'Georgia,serif',fontSize:18,fontWeight:700,color:'#1a1a2e',flex:1}}>{pageLabels[page]||page}</div>
          <div style={{fontFamily:'monospace',fontSize:12,color:'#8892a4',background:'#f8f9fa',padding:'4px 10px',borderRadius:20,border:'1px solid #e2e5ec'}}>{clock}</div>
        </div>
        <div style={{flex:1,padding:'18px 22px',animation:'fadeIn .25s ease'}}>
          {page==='dash'&&<DashPage db={db} session={session}/>}
          {page==='news'&&<NewsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='events'&&<EventsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='students'&&<StudentsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='teachers'&&<TeachersPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='admins'&&<AdminsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='subjects'&&<SubjectsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='entry'&&<EntryPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='affective'&&<AffectivePage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='results'&&<ResultsPage db={db} setDb={setDb} session={session} toast={showToast} onViewPrint={handleViewPrint}/>}
          {page==='classroom'&&<ClassroomPage db={db}/>}
          {page==='approval'&&<ApprovalPage db={db} setDb={setDb} toast={showToast} onViewPrint={handleViewPrint}/>}
          {page==='reports'&&<ReportsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='settings'&&<SettingsPage db={db} setDb={setDb} session={session} toast={showToast}/>}
          {page==='logs'&&<LogsPage db={db} setDb={setDb} session={session}/>}
          {page==='parent-home'&&<ParentHomePage db={db} setDb={setDb} session={session} toast={showToast} onViewPrint={handleViewPrint}/>}
          {page==='student-view'&&<StudentViewPage db={db} session={session} onViewPrint={handleViewPrint}/>}
          {page==='print'&&printData&&(
            <div>
              <div style={{display:'flex',gap:8,marginBottom:14}}>
                <Btn cls="pri" onClick={()=>window.print()}>🖨️ Print</Btn>
                <Btn onClick={()=>setPage(session.loginType==='parent'?'parent-home':'results')}>← Back</Btn>
              </div>
              <ResultSheet db={db} stuId={printData.sid} term={printData.term} sess={printData.sess}/>
            </div>
          )}
        </div>
      </div>
      <Toast t={toast_}/>
    </div>
  );
}
